
using Microsoft.Extensions.Hosting;
using BuildingBlocks.Authentication;using BuildingBlocks.Endpoints;using BuildingBlocks.Export;using BuildingBlocks.Grids;using BuildingBlocks.Http;using BuildingBlocks.Ledger;using BuildingBlocks.Modules;using BuildingBlocks.Persistence;using Microsoft.AspNetCore.Builder;using Microsoft.AspNetCore.Http;using Microsoft.AspNetCore.Routing;using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Design;using Microsoft.Extensions.Configuration;using Microsoft.Extensions.DependencyInjection;using SharedKernel;
namespace Workers;
/// <summary>Worker aggregate.</summary>
public sealed class Worker:AggregateRoot{public string Name{get;private set;}=string.Empty;public string? JobTitle{get;private set;}public bool IsActive{get;private set;}public DateTime CreatedAtUtc{get;private set;}public DateTime UpdatedAtUtc{get;private set;}private Worker(){}private Worker(string name,string? title):base(Guid.NewGuid()){Name=name;JobTitle=Norm(title);IsActive=true;CreatedAtUtc=UpdatedAtUtc=DateTime.UtcNow;}public static Result<Worker>Create(string? name,string? title)=>string.IsNullOrWhiteSpace(name)?Error.Validation("workers.name_required","Name is required."):new Worker(name.Trim(),title);public Result<Worker>Update(string? name,string? title,bool active){if(string.IsNullOrWhiteSpace(name))return Error.Validation("workers.name_required","Name is required.");Name=name.Trim();JobTitle=Norm(title);IsActive=active;UpdatedAtUtc=DateTime.UtcNow;return this;}private static string?Norm(string? x)=>string.IsNullOrWhiteSpace(x)?null:x.Trim();}
/// <summary>Worker advance.</summary>
public sealed class Advance:AggregateRoot{public Guid WorkerId{get;private set;}public decimal Amount{get;private set;}public DateOnly Date{get;private set;}public string? Notes{get;private set;}public Guid LinkedExpenseId{get;private set;}private Advance(){}public Advance(Guid workerId,decimal amount,DateOnly date,string? notes,Guid expenseId):base(Guid.NewGuid()){WorkerId=workerId;Amount=amount;Date=date;Notes=notes;LinkedExpenseId=expenseId;}}
/// <summary>Advance settlement.</summary>
public sealed class Settlement:AggregateRoot{public Guid WorkerId{get;private set;}public decimal Amount{get;private set;}public DateOnly Date{get;private set;}public string? Notes{get;private set;}private Settlement(){}public Settlement(Guid workerId,decimal amount,DateOnly date,string? notes):base(Guid.NewGuid()){WorkerId=workerId;Amount=amount;Date=date;Notes=notes;}}
/// <summary>Worker response. Init-only members so the grid projection (with the balance subquery)
/// stays translatable for EF Core filtering/sorting; a positional-constructor projection forces
/// client evaluation and throws "could not be translated".</summary>
public sealed record WorkerResponse
{
    public Guid Id { get; init; }
    public string Name { get; init; } = string.Empty;
    public string? JobTitle { get; init; }
    public bool IsActive { get; init; }
    public decimal Balance { get; init; }
    public DateTime CreatedAtUtc { get; init; }
    public DateTime UpdatedAtUtc { get; init; }
}
/// <summary>Worker request.</summary>
public sealed record WorkerRequest(string Name,string? JobTitle,bool IsActive=true);
/// <summary>Advance request.</summary>
public sealed record AdvanceRequest(decimal Amount,DateOnly Date,string? Notes,Guid ExpenseTypeId);
/// <summary>Settlement request.</summary>
public sealed record SettlementRequest(decimal Amount,DateOnly Date,string? Notes);
/// <summary>Worker report request.</summary>
public sealed record WorkerReportRequest(Guid WorkerId,DateOnly? From,DateOnly? To);
/// <summary>Worker export request.</summary>
public sealed record WorkerReportExportRequest(Guid WorkerId,DateOnly? From,DateOnly? To,ExportFormat Format,string WorkerName);
/// <summary>Worker transaction.</summary>
public sealed record WorkerTransaction(Guid Id,DateOnly Date,string Kind,decimal Amount,string? Notes,decimal RunningBalance);
/// <summary>Worker report.</summary>
public sealed record WorkerReportResponse(decimal TotalAdvances,decimal TotalSettlements,decimal Balance,IReadOnlyList<WorkerTransaction> Transactions);
/// <summary>Workers module.</summary>
public sealed class WorkersModule:IModule{public string Name=>"Workers";public void Register(IServiceCollection s,IConfiguration c){s.AddHostedService<WorkersSeedService>();}public void MapEndpoints(IEndpointRouteBuilder e)=>e.MapEndpointsFromAssembly(typeof(WorkersModule).Assembly);}
/// <summary>Worker endpoints.</summary>
public sealed class WorkersEndpoints:IEndpoint{private static IQueryable<WorkerResponse>Query(IMainDbContext db)=>db.Set<Worker>().AsNoTracking().Select(x=>new WorkerResponse{Id=x.Id,Name=x.Name,JobTitle=x.JobTitle,IsActive=x.IsActive,Balance=(db.Set<Advance>().Where(a=>a.WorkerId==x.Id).Sum(a=>(decimal?)a.Amount)??0)-(db.Set<Settlement>().Where(s=>s.WorkerId==x.Id).Sum(s=>(decimal?)s.Amount)??0),CreatedAtUtc=x.CreatedAtUtc,UpdatedAtUtc=x.UpdatedAtUtc});private static readonly GridFieldMap<WorkerResponse>Map=new(new[]{(new GridField("name","الاسم",GridFieldType.Text,true),(System.Linq.Expressions.Expression<Func<WorkerResponse,object?>>)(x=>x.Name)),(new GridField("jobTitle","المسمى الوظيفي",GridFieldType.Text,true),(System.Linq.Expressions.Expression<Func<WorkerResponse,object?>>)(x=>x.JobTitle)),(new GridField("isActive","نشط",GridFieldType.Boolean,false),(System.Linq.Expressions.Expression<Func<WorkerResponse,object?>>)(x=>x.IsActive)),(new GridField("balance","الرصيد",GridFieldType.Number,false),(System.Linq.Expressions.Expression<Func<WorkerResponse,object?>>)(x=>x.Balance))});public void MapEndpoint(IEndpointRouteBuilder app){var g=app.MapGroup("/api/workers").WithTags("Workers");g.MapPost("",Create).RequirePermission("workers.write");g.MapPut("/{id:guid}",Update).RequirePermission("workers.write");g.MapDelete("/{id:guid}",Delete).RequirePermission("workers.delete");g.MapGet("/{id:guid}",Get).RequirePermission("workers.read");g.MapPost("/grid",Grid).RequirePermission("workers.read");g.MapPost("/{id:guid}/advances",Advance).RequirePermission("workers.write");g.MapPost("/{id:guid}/settlements",Settle).RequirePermission("workers.write");g.MapPost("/report",Report).RequirePermission("workers.read");g.MapPost("/report/export",ExportReport).RequirePermission("workers.export");}private static async Task<IResult>Create(WorkerRequest r,IMainDbContext db,CancellationToken ct){var x=Worker.Create(r.Name,r.JobTitle);if(x.IsFailure)return Results.BadRequest(x.Error);x.Value.Update(r.Name,r.JobTitle,r.IsActive);db.Add(x.Value);await db.SaveChangesAsync(ct);return Results.Created($"/api/workers/{x.Value.Id}",await Query(db).SingleAsync(v=>v.Id==x.Value.Id,ct));}private static async Task<IResult>Update(Guid id,WorkerRequest r,IMainDbContext db,CancellationToken ct){var x=await db.Set<Worker>().FindAsync([id],ct);if(x is null)return Results.NotFound();var z=x.Update(r.Name,r.JobTitle,r.IsActive);if(z.IsFailure)return Results.BadRequest(z.Error);await db.SaveChangesAsync(ct);return Results.Ok(await Query(db).SingleAsync(v=>v.Id==id,ct));}private static async Task<IResult>Delete(Guid id,IMainDbContext db,CancellationToken ct){var x=await db.Set<Worker>().FindAsync([id],ct);if(x is null)return Results.NotFound();if(await db.Set<Advance>().AnyAsync(a=>a.WorkerId==id,ct)||await db.Set<Settlement>().AnyAsync(a=>a.WorkerId==id,ct))return Results.Conflict();db.Remove(x);await db.SaveChangesAsync(ct);return Results.NoContent();}private static async Task<IResult>Get(Guid id,IMainDbContext db,CancellationToken ct){var x=await Query(db).SingleOrDefaultAsync(v=>v.Id==id,ct);return x is null?Results.NotFound():Results.Ok(x);}private static async Task<IResult>Grid(GridQuery r,IMainDbContext db,CancellationToken ct){var q=Query(db).ApplyGridQuery(r,Map);if(q.IsFailure)return q.ToHttpResult();return Results.Ok(await q.Value.ToPagedResultAsync(r,x=>x,ct));}private static async Task<IResult>Advance(Guid id,AdvanceRequest r,IMainDbContext db,ILedgerWriter writer,CancellationToken ct){var w=await db.Set<Worker>().FindAsync([id],ct);if(w is null)return Results.NotFound();if(r.Amount<=0)return Results.BadRequest();var expenseId=await writer.CreateExpenseAsync(OwnerType.Worker,id,r.ExpenseTypeId,r.Amount,r.Date,w.Name,r.Notes,ct);var x=new Advance(id,r.Amount,r.Date,r.Notes,expenseId);db.Set<Advance>().Add(x);await db.SaveChangesAsync(ct);return Results.Created($"/api/workers/{id}/advances/{x.Id}",x);}private static async Task<IResult>Settle(Guid id,SettlementRequest r,IMainDbContext db,CancellationToken ct){if(!await db.Set<Worker>().AnyAsync(x=>x.Id==id,ct))return Results.NotFound();var balance=(await db.Set<Advance>().Where(x=>x.WorkerId==id).SumAsync(x=>(decimal?)x.Amount,ct)??0)-(await db.Set<Settlement>().Where(x=>x.WorkerId==id).SumAsync(x=>(decimal?)x.Amount,ct)??0);if(r.Amount<=0||r.Amount>balance)return Results.BadRequest();var x=new Settlement(id,r.Amount,r.Date,r.Notes);db.Set<Settlement>().Add(x);await db.SaveChangesAsync(ct);return Results.Created($"/api/workers/{id}/settlements/{x.Id}",x);}private static async Task<WorkerReportResponse>Build(WorkerReportRequest r,IMainDbContext db,CancellationToken ct){var advances=db.Set<Advance>().AsNoTracking().Where(x=>x.WorkerId==r.WorkerId);var settlements=db.Set<Settlement>().AsNoTracking().Where(x=>x.WorkerId==r.WorkerId);if(r.From.HasValue){advances=advances.Where(x=>x.Date>=r.From);settlements=settlements.Where(x=>x.Date>=r.From);}if(r.To.HasValue){advances=advances.Where(x=>x.Date<=r.To);settlements=settlements.Where(x=>x.Date<=r.To);}var raw=(await advances.Select(x=>new{x.Id,x.Date,Kind="سلفة",x.Amount,x.Notes,Sign=1}).Concat(settlements.Select(x=>new{x.Id,x.Date,Kind="تسوية",x.Amount,x.Notes,Sign=-1})).OrderBy(x=>x.Date).ToListAsync(ct));decimal running=0;var rows=raw.Select(x=>{running+=x.Amount*x.Sign;return new WorkerTransaction(x.Id,x.Date,x.Kind,x.Amount,x.Notes,running);}).ToArray();var a=raw.Where(x=>x.Sign==1).Sum(x=>x.Amount);var s=raw.Where(x=>x.Sign==-1).Sum(x=>x.Amount);return new(a,s,a-s,rows);}private static async Task<IResult>Report(WorkerReportRequest r,IMainDbContext db,CancellationToken ct)=>Results.Ok(await Build(r,db,ct));private static async Task<IResult>ExportReport(WorkerReportExportRequest r,IMainDbContext db,IGridExporterFactory f,CancellationToken ct){var x=await Build(new(r.WorkerId,r.From,r.To),db,ct);var cols=new[]{new ExportColumn("Date","التاريخ",GridFieldType.Date),new ExportColumn("Kind","النوع",GridFieldType.Text),new ExportColumn("Amount","المبلغ",GridFieldType.Number),new ExportColumn("RunningBalance","الرصيد",GridFieldType.Number)};var bytes=f.For(r.Format).Export(x.Transactions,cols,$"تقرير العامل {r.WorkerName}");return Results.File(bytes,r.Format==ExportFormat.Xlsx?"application/vnd.openxmlformats-officedocument.spreadsheetml.sheet":"application/pdf",$"worker-report.{(r.Format==ExportFormat.Xlsx?"xlsx":"pdf")}");}}
/// <summary>Seeds workers.</summary>
public sealed class WorkersSeedService(IServiceProvider services):IHostedService{public async Task StartAsync(CancellationToken ct){using var scope=services.CreateScope();var db=scope.ServiceProvider.GetRequiredService<IMainDbContext>();if(await db.Set<Worker>().AnyAsync(ct))return;db.Set<Worker>().AddRange(Worker.Create("أحمد محمد","عامل إنتاج").Value,Worker.Create("محمود علي","سائق").Value);await db.SaveChangesAsync(ct);}public Task StopAsync(CancellationToken ct)=>Task.CompletedTask;}


